var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"정말 너무 실망스럽네…….","JPN":"本当にガッカリだわ……","ENG":"Truly disappointing...","TWN":"真令人失望……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"악몽을 꾸지 않게 해주는 거라면 정말 유용하게 쓰일 텐데.","JPN":"悪夢を見ないようにしてくれるのなら、本当に使えそうなのに。","ENG":"She would’ve been very useful to me if she really could get rid of nightmares.","TWN":"若是真能夠消除惡夢，或許還有用武之地。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"애들 좀 잘 회수해 줘요. 너무 많이 다치지 않게 조심해 주시고요.","JPN":"子どもたちをちゃんと回収してくださいね。あまり怪我させないように気をつけて。","ENG":"You can go retrieve the kids now. But be careful not the hurt them.","TWN":"把她們帶回去吧，小心不要出手太重。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아니면…… 아예 편하게 보내주는 것도 좋겠네요. 이제 딱히 쓸모도 없는데.","JPN":"それとも……楽にしてあげるのもいいですね。もう役にも立たないし。","ENG":"Or... Maybe get them out of their misery. I don't need them any longer.","TWN":"或是……讓她們安靜離開也無妨，畢竟已經毫無利用價值。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"말씀하신대로 처리하겠습니다.","JPN":"おっしゃったとおりに処理します。","ENG":"As you command.","TWN":"我們會照夫人說的處理乾淨。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"그럼…….","JPN":"それじゃあ……","ENG":"Then...","TWN":"那……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"잠깐만요.","JPN":"ちょっと。","ENG":"Hold on.","TWN":"先等一下。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"무슨 일이십니까?","JPN":"どうなさいましたか？","ENG":"What’s wrong, Madam?","TWN":"還有什麼吩咐嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"잠깐…….","JPN":"待って……","ENG":"Wait a minute...","TWN":"等等……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"어쩐지 개운하네요?","JPN":"なんだかすっきりしてるわね？","ENG":"I feel... refreshed?","TWN":"怎麼有種神清氣爽的感覺？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"무슨 말씀을……?","JPN":"それはどういう……？","ENG":"I don’t understand...","TWN":"夫人的意思是……？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님과 일하면서부터 한 번도 제대로 잔 적이 없었거든요. 매일매일 고민거리가 쌓여서 말이죠.","JPN":"ヘイブン様と働いて以来、一度もちゃんと眠ったことがないのですよ。毎日毎日、悩みが多くなってね。","ENG":"I haven't gotten a good night's sleep since I started working with Mr. Haven. Every second of the day is spent worrying.","TWN":"自從我跟著天堂先生做事後，就從來沒睡過覺，每天都有滿滿的事在等著我去煩。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그런데…… 마치 잘자고 일어난 것처럼 개운해요.","JPN":"でも……まるでよく眠って起きたようにすっきりしてるわ。","ENG":"But right now... I feel refreshed, as if I had woken up from one.","TWN":"可是……我現在的感覺，就像睡飽覺後起床那般舒暢。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"제가 얼마나 있다가 나왔죠?","JPN":"私がどのくらい中にいましたか？","ENG":"How long was I in there for?","TWN":"我在裡面待多久？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"10분도 채 안 계셨습니다.","JPN":"10分もいらっしゃいませんでした。","ENG":"Less than 10 minutes, Madam.","TWN":"不到10分鐘"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"10분?","JPN":"10分？","ENG":"10 minutes?","TWN":"10分鐘？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"10분만에 묵은 피로가 거짓말처럼 사라졌다는 건……","JPN":"10分でたまった疲れが噓のように消えたということは……","ENG":"If it only took 10 minutes to make my exhaustion vanish...","TWN":"10分鐘內就能夠疲勞盡失……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};